const express = require('express');
const { graphqlHTTP } = require('express-graphql');
const { buildSchema } = require('graphql');
const { Pool } = require('pg');

// replace these with your postgresql configuration
const pool = new Pool({
  user: 'user',
  host: 'localhost',
  database: 'database',
  password: 'password',
  port: 5432,
});

// define schema
const schema = buildSchema(`
  type Query {
    posts: [Post!]
  }

  type Post {
    id: Int!
    title: String!
    author: Author!
  }

  type Author {
    name: String!
  }
`);

// define resolvers
const root = {
  posts: async () => {
    const result = await pool.query('SELECT * FROM posts');
    return result.rows;
  },
};

const app = express();
app.use('/graphql', graphqlHTTP({ schema, rootValue: root, graphiql: true }));
app.listen(4000);